package main

import (
	"fmt"
	"slices"
)

// Sort each substring of s2 and compare with sorted s1. This is a brute-force approach and is inefficient for large strings.
// Time Complexity: O(n^3 logn) where n is the length of s2, since we sort each substring of length len(s1) and there are O(n) such substrings.
// Space Complexity: O(n) for the temporary slice used for sorting each substring.
func checkInclusionBruteForce(s1 string, s2 string) bool {
	runes := []rune(s1)
	runes2 := []rune(s2)

	if len(runes) > len(runes2) {
		return false
	}

	slices.Sort(runes)

	for i := 0; i < len(runes2); i++ {
		tempSlice := make([]rune, len(runes))
		copy(tempSlice, runes2[i:min(i+len(runes), cap(runes2))])
		slices.Sort(tempSlice)
		if string(tempSlice) == string(runes) {
			return true
		}
	}
	return false
}

// checkInclusionSlidingWindow returns true if any substring of s2 is a permutation of s1.
// It uses two fixed-size frequency arrays (26 lowercase letters) and a sliding window of len(s1).
// Time Complexity: O(n) where n is the length of s2, since we traverse s2 once.
// Space Complexity: O(1) since the frequency arrays are of fixed size (26).
func checkInclusionSlidingWindow(s1 string, s2 string) bool {
	// If s1 is longer, no window in s2 can match it.
	if len(s1) > len(s2) {
		return false
	}

	s1Count := make([]int, 26)
	s2Count := make([]int, 26)
	// Build character counts for s1 and the first window in s2.
	for i := 0; i < len(s1); i++ {
		s1Count[s1[i]-'a']++
		s2Count[s2[i]-'a']++
	}

	matches := 0
	// Count how many character buckets already match between s1 and the first window.
	for i := 0; i < 26; i++ {
		if s1Count[i] == s2Count[i] {
			matches++
		}
	}

	l := 0
	// Expand window with r, then shrink from l to keep window size constant.
	for r := len(s1); r < len(s2); r++ {
		// All 26 buckets match, so current window is a permutation.
		if matches == 26 {
			return true
		}

		// Add new right-side character into the window and adjust matches.
		index := s2[r] - 'a'
		s2Count[index]++
		if s1Count[index] == s2Count[index] {
			matches++
		} else if s1Count[index]+1 == s2Count[index] {
			matches--
		}

		// Remove left-side character from the window and adjust matches.
		index = s2[l] - 'a'
		s2Count[index]--
		if s1Count[index] == s2Count[index] {
			matches++
		} else if s1Count[index]-1 == s2Count[index] {
			matches--
		}
		l++
	}
	// Check the final window after loop completion.
	return matches == 26
}

func main() {
	s1, s2 := "abc", "lecabee"
	fmt.Println(checkInclusionBruteForce(s1, s2))
	fmt.Println(checkInclusionSlidingWindow(s1, s2))

	s1, s2 = "abc", "lecaabee"
	fmt.Println(checkInclusionBruteForce(s1, s2))
	fmt.Println(checkInclusionSlidingWindow(s1, s2))

	s1, s2 = "", ""
	fmt.Println(checkInclusionBruteForce(s1, s2))
	fmt.Println(checkInclusionSlidingWindow(s1, s2))

	s1, s2 = "", ""
	fmt.Println(checkInclusionBruteForce(s1, s2))
	fmt.Println(checkInclusionSlidingWindow(s1, s2))

}
